func tenantIDFrom(c *gin.Context) (uint64, bool) {
	tid := c.GetUint64(types.TenantIDContextKey.String())
	if tid == 0 {
		c.Error(errors.NewBadRequestError("Tenant ID cannot be empty"))
		return 0, false
	}
	return tid, true
}

