// ListAllTools godoc
// @Summary   获取所有工具（按库分组）
// @Tags      工具
// @Success   200  {object}  map[string]interface{}
// @Router    /tools [get]
func (h *ToolHandler) ListAllTools(c *gin.Context) {
	ctx := c.Request.Context()
	tid, ok := tenantIDFrom(c)
	if !ok {
		return
	}
	libs, err := h.toolService.ListAllTools(ctx, tid)
	if err != nil {
		logger.ErrorWithFields(ctx, err, map[string]interface{}{"tenant_id": tid})
		c.Error(errors.NewInternalServerError("Failed to list tools: " + err.Error()))
		return
	}
	c.JSON(http.StatusOK, gin.H{"success": true, "data": libs})
}

